const { Client } = require('@elastic/elasticsearch');
const { validateSearchParams } = require('./search-param-validator');

async function search(esClient, indexName, searchParams) {
  try {
    const validatedSearchParams = await validateSearchParams(searchParams);
    const query = buildQuery(validatedSearchParams);

    const result = await esClient.search({
      index: indexName,
      body: { query }
    });

    if (searchParams.customScoringScript) {
      const scriptScoreResult = await applyCustomScoringScript(esClient, indexName, searchParams.customScoringScript);
      return combineResults(result.hits.hits, scriptScoreResult.hits.hits);
    }

    return result;
  } catch (error) {
    console.error('Error searching:', error);
    throw error;
  }
}

function buildQuery(searchParams) {
  const query = {
    bool: {
      filter: [],
      must: []
    }
  };

  if (searchParams.query) {
    query.bool.must.push({ match: { _all: searchParams.query } });
  }

  if (searchParams.fields) {
    Object.keys(searchParams.fields).forEach(field => {
      const value = searchParams.fields[field];
      if (value !== null && value !== undefined) {
        query.bool.filter.push({
          term: {
            [field]: value
          }
        });
      }
    });
  }

  return query;
}

async function applyCustomScoringScript(esClient, indexName, scriptLogic) {
  const script = {
    script_score: {
      script: {
        source: scriptLogic,
        lang: 'painless'
      },
      fields: ['_score']
    }
  };

  const result = await esClient.search({
    index: indexName,
    body: { query: script }
  });

  return result;
}

function combineResults(hits1, hits2) {
  const combinedHits = hits1.concat(hits2);
  combinedHits.sort((a, b) => a._score - b._score);
  return { hits: combinedHits };
}

